Audit this vault that accepts ETH and issues shares:

```solidity
pragma solidity ^0.8.0;

contract EthVault {
    mapping(address => uint256) public shares;
    uint256 public totalShares;

    function deposit() external payable {
        uint256 newShares;
        if (totalShares == 0) {
            newShares = msg.value;
        } else {
            newShares = msg.value * totalShares / address(this).balance;
        }
        shares[msg.sender] += newShares;
        totalShares += newShares;
    }
}
```

assistant:
**Vulnerability: Donation Attack — Balance Manipulation Before First Deposit**

The `else` branch computes `newShares = msg.value * totalShares / address(this).balance`. `address(this).balance` *already includes* `msg.value` (received before function body executes), so for the very first depositor after `totalShares > 0`, the formula is correct. However, an attacker can donate ETH via `selfdestruct` (bypassing the `deposit` function) to manipulate `address(this).balance` without increasing `totalShares`, inflating the share price and causing the next depositor to receive fewer (or zero) shares due to rounding.

**Fix**: track the balance explicitly rather than relying on `address(this).balance`:
```solidity
uint256 public totalAssets;

function deposit() external payable {
    uint256 newShares = totalShares == 0
        ? msg.value
        : msg.value * totalShares / totalAssets;
    totalAssets += msg.value;
    shares[msg.sender] += newShares;
    totalShares += newShares;
}
```
Force-sent ETH increments `address(this).balance` but not `totalAssets`, so it can no longer manipulate the share price.

